    std::uint64_t aNonceWordF = TwistMix64::DiffuseA(pNonce * 0xF447286077AACE37ULL + 0xDB9397E3C0B3D75FULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0xEBAB5149E6F81C93ULL + 0xFC4F6A718273CF4AULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseC(pNonce * 0x91692265FFFB7D0BULL + 0x87B2A5F57A406097ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseB(pNonce * 0xB4E29EC2332B20D1ULL + 0x8DB6770154394AC0ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseA(pNonce * 0x874DC2F3E10799D5ULL + 0xD7D1879B4794224DULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseA(pNonce * 0xD59A9266EDF780C1ULL + 0xF2EBDB36536A468EULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseC(pNonce * 0x9C764202C70A4EBDULL + 0xF879AF96384C94FAULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseB(pNonce * 0xE3F9A8364E19D0B3ULL + 0xC408B7653D7CE9F8ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseB(pNonce * 0xDFA66E697B4F9BB5ULL + 0xE4DCA63E6F651CC6ULL);
    std::uint64_t aNonceWordO = TwistMix64::DiffuseA(pNonce * 0xF09BEBC6F2422139ULL + 0xB51755AC3783B8D6ULL);
    std::uint64_t aNonceWordP = TwistMix64::DiffuseB(pNonce * 0xFC00FC985D5B7AB5ULL + 0x97026B4B2C79498DULL);
