            aCross = RotL64(pSnow[((S_BLOCK1 - aIndex + 2821U)) & S_BLOCK1], 51U) ^ RotL64(aSource[((S_BLOCK1 - aIndex + 3152U)) & S_BLOCK1], 60U);
