            aOrbiterA = (aWandererC + RotL64(aIngress, 51U)) + 9037046235160478893U;
            aOrbiterG = ((aWandererA + RotL64(aScatter, 5U)) + 17604625254797481563U) + aOrbiterAssignSaltF[(((31U - aIndex) + 19U)) & S_SALT1];
            aOrbiterB = (aWandererH + RotL64(aCross, 18U)) + 15989810521620839842U;
            aOrbiterJ = ((aWandererF + RotL64(aPrevious, 35U)) + RotL64(aCarry, 23U)) + 13911887025625988629U;
            aOrbiterH = ((aWandererG + RotL64(aScatter, 39U)) + RotL64(aCarry, 37U)) + 18364841797744693826U;
