            aOrbiterJ = (aOrbiterJ + aOrbiterH) + 4087671580643514042U;
            aOrbiterD = (aOrbiterD ^ aOrbiterJ) ^ 202038027430949790U;
            aOrbiterD = RotL64((aOrbiterD * 3196314734973520765U), 23U);
            //
            aOrbiterG = ((aOrbiterG + aOrbiterE) + 18139600905611302045U) + aNonceWordL;
            aOrbiterI = (aOrbiterI ^ aOrbiterG) ^ 15989780459528584935U;
            aOrbiterI = RotL64((aOrbiterI * 1001819858363813739U), 47U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterI) + 6855949497614695124U;
            aOrbiterC = (aOrbiterC ^ aOrbiterB) ^ 1050578692510030969U;
            aOrbiterC = RotL64((aOrbiterC * 8673704862875548963U), 51U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterK) + 17264173175418150631U;
            aOrbiterG = (aOrbiterG ^ aOrbiterC) ^ 12166084050082431225U;
            aOrbiterG = RotL64((aOrbiterG * 12019026290520229047U), 5U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterD) + 17180472982632226191U;
            aOrbiterE = ((aOrbiterE ^ aOrbiterK) ^ 12848842219908604063U) ^ aOrbiterUpdateSaltB[(((31U - aIndex) + 21U)) & S_SALT1];
            aOrbiterE = RotL64((aOrbiterE * 9435793531702548201U), 19U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterF) + 17457437519922113886U;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterE) ^ 11373965200840038086U) ^ aOrbiterUpdateSaltF[(((31U - aIndex) + 15U)) & S_SALT1];
            aOrbiterJ = RotL64((aOrbiterJ * 11162942107764134359U), 53U);
            //
            aOrbiterF = ((aOrbiterF + aOrbiterB) + 2455733816897468133U) + aNonceWordE;
