            //
            aOrbiterH = (aOrbiterH + aOrbiterC) + 5612732012613144158U;
            aOrbiterA = ((aOrbiterA ^ aOrbiterH) ^ 11661322725433857164U) ^ aOrbiterUpdateSaltC[((aIndex + 5U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 12508289317128089311U), 29U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterJ) + 16164776489850010059U;
