            //
            aOrbiterD = ((aOrbiterD + aOrbiterA) + 16088063614816830618U) + aOrbiterUpdateSaltE[((aIndex + 3U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterD) ^ 6819024669233769937U;
            aOrbiterF = RotL64((aOrbiterF * 16326845970660356337U), 43U);
            //
            aIngress = aOrbiterC ^ RotL64(aOrbiterB, 18U);
            aIngress = aIngress + (RotL64(aOrbiterF, 35U) ^ aOrbiterG);
